const fc = msg.payload;
if (!fc || fc.type !== 'FeatureCollection' || !Array.isArray(fc.features)) {
    node.warn('NOAA: unexpected payload shape');
    return null;
}

function fmt(feature) {
    const p = feature.properties || {};
    const headline = p.headline || p.event || 'Weather Alert';
    const desc = (p.description || '').replace(/\s+/g, ' ').trim().slice(0, 600);
    const instr = (p.instruction || '').replace(/\s+/g, ' ').trim().slice(0, 300);
    const sent = p.sent || '';
    const expires = p.expires || '';
    const area = p.areaDesc || '';
    const remarks = [
        headline,
        area && `Area: ${area}`,
        (p.severity || p.certainty) && `Severity: ${p.severity || '?'} / Certainty: ${p.certainty || '?'}`,
        sent && `Sent: ${sent}`,
        expires && `Expires: ${expires}`,
        desc && `\n${desc}`,
        instr && `\nInstruction: ${instr}`
    ].filter(Boolean).join(' | ');
    feature.id = p.id || feature.id;
    feature.properties = {
        ...p,
        callsign: p.event || 'Weather Alert',
        remarks: remarks
    };
    return feature;
}

// NOAA returns alerts even when no polygon is present (area-based alerts without geometry).
// Drop those — can't plot a shape without coordinates.
const withGeom = fc.features.filter(f => f.geometry && f.geometry.type === 'Polygon');
msg.payload = {
    type: 'FeatureCollection',
    features: withGeom.map(fmt)
};
return msg;
